const { createHmac, timingSafeEqual } = require('crypto');
const auth = $input.item.json.headers?.authorization || '';
const token = auth.replace(/^Bearer\s+/i, '').trim();
const secret = $env.JWT_SECRET;

if (!token) { $input.item.json.jwtValid = false; $input.item.json.jwtError = 'missing'; return $input.item; }

const parts = token.split('.');
if (parts.length !== 3) { $input.item.json.jwtValid = false; $input.item.json.jwtError = 'malformed'; return $input.item; }

const [h, p, s] = parts;
const expected = createHmac('sha256', secret).update(`${h}.${p}`).digest('base64url');
const eBuf = Buffer.from(expected); const aBuf = Buffer.from(s);
if (eBuf.length !== aBuf.length || !timingSafeEqual(eBuf, aBuf)) { $input.item.json.jwtValid = false; $input.item.json.jwtError = 'invalid_sig'; return $input.item; }

const payload = JSON.parse(Buffer.from(p, 'base64url').toString());
if (payload.exp < Math.floor(Date.now() / 1000)) { $input.item.json.jwtValid = false; $input.item.json.jwtError = 'expired'; return $input.item; }

$input.item.json.jwtValid = true;
return $input.item;
